import React, { useState } from 'react';
import { GraduationCap, Upload, Plus, Edit, Trash2, Users, Star, DollarSign, BookOpen, TrendingUp, BarChart3, PieChart, X, Video, Link, FileVideo, Eye, Play, Save } from 'lucide-react';

const InstructorPage = ({ courses, onAddCourse, onUpdateCourse, onDeleteCourse }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [showUploadModal, setShowUploadModal] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [showCourseModal, setShowCourseModal] = useState(false);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [dragActive, setDragActive] = useState(false);
  const [thumbnailDragActive, setThumbnailDragActive] = useState(false);
  const [courseForm, setCourseForm] = useState({
    title: '',
    desc: '',
    price: '',
    cat: 'development',
    level: 'Beginner',
    time: '',
    instructor: 'Current User',
    img: 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3?w=400&h=200&fit=crop',
    videoUrl: '',
    videoType: 'link'
  });

  const instructorStats = {
    totalCourses: courses.length,
    totalStudents: courses.reduce((sum, course) => sum + course.enrolled, 0),
    totalRevenue: courses.reduce((sum, course) => sum + (course.price * course.enrolled), 0),
    avgRating: courses.length > 0 ? (courses.reduce((sum, course) => sum + parseFloat(course.rating), 0) / courses.length).toFixed(1) : '0.0'
  };

  const handleSubmit = (e) => {
    e.preventDefault();
